## Phase 10: Launcher Scripts

### launch-chyren.sh (Linux/macOS)
```bash
#!/bin/bash
# Detects workspace, sets environment, launches Chyren

WORKSPACE_ROOT="${OMEGA_ROOT:-/CHYREN/workspace/OmegA-Next}"
SIDECAR_PORT="${OMEGA_SIDECAR_PORT:-9000}"
GATEWAY_PORT="${OMEGA_GATEWAY_PORT:-8000}"

# Detect USB workspace marker (optional)
if [ -n "$USB_MARKER" ]; then
    WORKSPACE_ROOT=$(find /mnt -name "$USB_MARKER" -type d 2>/dev/null | head -1)
    if [ -z "$WORKSPACE_ROOT" ]; then
        echo "ERROR: USB workspace marker '$USB_MARKER' not found"
        exit 1
    fi
fi

export OMEGA_ROOT="$WORKSPACE_ROOT"
export OMEGA_HOST_CACHE="${XDG_CACHE_HOME:-$HOME/.cache}/omega"
export OMEGA_SIDECAR_URL="http://127.0.0.1:$SIDECAR_PORT"
export RUST_LOG="omega=debug,info"

cd "$WORKSPACE_ROOT"

# Launch sidecar (background)
echo "Starting Python sidecar on port $SIDECAR_PORT..."
cd sidecar/omega-sidecar
python3 -m venv venv 2>/dev/null || true
source venv/bin/activate
pip install -q -r requirements.txt
python3 main.py --port $SIDECAR_PORT &
SIDECAR_PID=$!

# Launch gateway
echo "Building gateway..."
cd ../../crates/omega-gateway
cargo build --release 2>&1 | grep -v "warning:"

echo "Starting gateway on port $GATEWAY_PORT..."
cargo run --release -- --port $GATEWAY_PORT

# Cleanup on exit
trap "kill $SIDECAR_PID 2>/dev/null; exit 0" SIGINT SIGTERM
wait
```

